n = int(input())
bumpers = input()
count = 0
for i in range(n):
    if bumpers[i] == '<':
        if i == 0:
            count += 1
        elif bumpers[i-1] == '<':
            count += 1
    else:
        if i == n-1:
            count += 1
        elif bumpers[i+1] == '>':
            count += 1
print(count)
